SELECT qid, exam_year, correct_letter, SUBSTR(question_text,1,60) as preview
FROM questions
WHERE qid IN ('QID-2020-0134','QID-2020-0138','QID-2021-0050','QID-2021-0168','QID-2022-0175','QID-2023-0004','QID-2024-0017','QID-2024-0117','QID-2024-0140','QID-2024-0187')
ORDER BY qid;